import*as React from"react";import{clamp}from"../helpers/math";import{rangeIncrement}from"../helpers/range";const usePagination=({currentPage:r=1,siblingCount:s=1,boundaryCount:m=1,totalPages:p=1}={})=>React.useMemo(()=>{var e=rangeIncrement(1,Math.min(m,p)),a=rangeIncrement(Math.max(p-m+1,m+1),p),n=clamp(r-s,m+2,p-m-1-2*s),t=Math.min(Math.max(r+s,m+2+2*s),0<a.length?a[0]-2:p-1);return m+2<n?e.push("start-ellipsis"):m+1<p-m&&e.push(m+1),e.push(...rangeIncrement(n,t)),t<p-m-1?e.push("end-ellipsis"):m<p-m&&e.push(p-m),e.push(...a),e},[r,p,s,m]);export{usePagination};